import{_ as i,n as d,v as l,ac as s}from"./chunks/framework.DFVDdn94.js";const a="/blog/devops/08.png",o="/blog/devops/09.jpg",t="/blog/devops/vi.png",c="/blog/devops/mode.png",n="/blog/devops/07.png",F=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"devops/03-linux.md","filePath":"devops/03-linux.md","lastUpdated":1751535949000}'),p={name:"devops/03-linux.md"};function h(r,e,k,u,g,b){return l(),d("div",null,e[0]||(e[0]=[s(`<h2 id="系统管理" tabindex="-1">系统管理 <a class="header-anchor" href="#系统管理" aria-label="Permalink to &quot;系统管理&quot;">​</a></h2><h3 id="free-查看内存使用情况" tabindex="-1">free 查看内存使用情况 <a class="header-anchor" href="#free-查看内存使用情况" aria-label="Permalink to &quot;free 查看内存使用情况&quot;">​</a></h3><p><code>free [ 选项 ]</code></p><ul><li><code>-b</code> 以 byte 显示内存使用情况</li><li><code>-k</code> 以 kb 显示内存使用情况</li><li><code>-m</code> 以 mb 显示内存使用情况</li><li><code>-s</code> 指定刷新间隔</li></ul><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">free</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -ms</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> 2</span></span></code></pre></div><h3 id="ps-查看进程" tabindex="-1">ps 查看进程 <a class="header-anchor" href="#ps-查看进程" aria-label="Permalink to &quot;ps 查看进程&quot;">​</a></h3><p><code>ps [ 选项 ]</code></p><ul><li><code>-ef</code> 显示所有进程</li><li><code>-u [ user ]</code> 显示指定用户进程</li><li><code>-au[ x ]</code> 显示所有包含其他使用者的进程</li></ul><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 查看所有进程过滤 nginx 进程</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">ps</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -ef</span><span style="--shiki-dark:#FF7B72;--shiki-light:#D73A49;"> |</span><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;"> grep</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> nginx</span></span></code></pre></div><p>结果分析</p><table tabindex="0"><thead><tr><th>标题</th><th>说明</th></tr></thead><tbody><tr><td>USER</td><td>用户名</td></tr><tr><td>PID</td><td>进程号</td></tr><tr><td>%CPU</td><td>占用 CPU 百分比</td></tr><tr><td>%MEM</td><td>占用内存百分比</td></tr><tr><td>VSZ</td><td>占用虚拟内存</td></tr><tr><td>RSS</td><td>占用物理内存</td></tr><tr><td>TTY</td><td>终端名</td></tr><tr><td>STAT</td><td>进程状态 <br> <code>D</code> 不可中断的睡眠状态，<br> <code>R</code> 正在运行， <br> <code>S</code> 睡眠，<br> <code>T</code> 跟踪/停止，<br> <code>Z</code> 僵尸进程 <br> <code>&lt;</code> 高优先级 <br> <code>N</code> 低优先级</td></tr><tr><td>START</td><td>启动时间</td></tr><tr><td>TIME</td><td>运行时间</td></tr><tr><td>COMMAND</td><td>所执行的指令</td></tr></tbody></table><h3 id="top-查看进程-实时" tabindex="-1">top 查看进程（实时） <a class="header-anchor" href="#top-查看进程-实时" aria-label="Permalink to &quot;top 查看进程（实时）&quot;">​</a></h3><p><code>top [ 选项 ]</code></p><ul><li><code>-d</code> 指定刷新间隔</li><li><code>-p</code> 指定进程号</li><li><code>-n</code> 指定刷新次数，到达次数后退出</li><li><code>-i</code> 不显示闲置或僵尸进程</li><li><code>-u</code> 显示指定用户名进程</li></ul><h3 id="kill-终止进程" tabindex="-1">kill 终止进程 <a class="header-anchor" href="#kill-终止进程" aria-label="Permalink to &quot;kill 终止进程&quot;">​</a></h3><p><code>kill [ 选项 ] 进程号</code> 默认会发送 <code>SIGTERM</code> 信号，默认是 <code>15</code> 也可以通过 <code>-[num]</code> 指定发送的信号</p><ul><li><code>-9</code> <code>SIGKILL</code> 立即结束进程，不能捕获或忽略</li><li><code>-15</code> <code>SIGTERM</code> 正常结束进程，可以捕获或忽略</li><li><code>-19</code> <code>SIGSTOP</code> 暂停进程，不能捕获、忽略或结束</li><li><code>-18</code> <code>SIGCONT</code> 继续运行暂停的进程</li></ul><h3 id="chmod-修改文件权限" tabindex="-1">chmod 修改文件权限 <a class="header-anchor" href="#chmod-修改文件权限" aria-label="Permalink to &quot;chmod 修改文件权限&quot;">​</a></h3><p><img src="`+a+'" alt="alt text"><img src="'+o+`" alt="alt text"></p><p><code>chmod 权限 文件名</code> 权限的修改整体分为三部分； <strong>给谁权限、增或减少权限、赋予什么权限</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><code>-u</code> 所有者 Owner；<code>-g</code> 所属组；<code>-o</code> 其他人；<code>-a</code> 所有人</p><p><code>+</code> 添加权限；<code>-</code> 减少权限；<code>=</code> 设置权限</p><p><code>r</code> 读权限；<code>w</code> 写权限；<code>x</code> 执行权限</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 给 a.txt 文件所有者添加执行权限</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">chmod</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> u+x</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> a.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 给所有用户添加读写执行权限</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">chmod</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> a+rwx</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> a.txt</span></span></code></pre></div><p>也可以通过 8 进制数字进行权限设置，<strong><code>1</code> 表示执行，<code>2</code> 表示写权限，<code>4</code> 表示读权限。(1 + 2 + 4 = 7)</strong>，常用组合如下。</p><ul><li><code>755: rwxr-xr-x</code></li><li><code>644: rw-r--r--</code></li><li><code>700: rwx------</code></li><li><code>777: rwxrwxrwx</code></li></ul><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 给 a.txt 文件所有用户增加执行权限</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">chmod</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> 111</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> a.txt</span></span></code></pre></div></div><h3 id="df-查看磁盘使用情况" tabindex="-1">df 查看磁盘使用情况 <a class="header-anchor" href="#df-查看磁盘使用情况" aria-label="Permalink to &quot;df 查看磁盘使用情况&quot;">​</a></h3><p><code>df [ 选项 ] [ 文件 ]</code></p><ul><li><code>-l</code> 进现实本地磁盘 (默认)</li><li><code>-a</code> 显示所有文件系统信息</li><li><code>-T</code> 显示磁盘分区类型</li><li><code>-t</code> 显示指定类型文件系统的磁盘分区</li><li><code>-H</code> 以 <code>1000</code> 进制显示</li><li><code>-h</code> 以 <code>1024</code> 进制显示</li><li><code>-x</code> 不显示指定文件类型的磁盘分区</li></ul><p>示例</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 以 1024 进制显示 /dev/shm 分区信息</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">df</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -ht</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> tmpfs</span></span></code></pre></div><h3 id="du-统计磁盘上文件大小" tabindex="-1">du 统计磁盘上文件大小 <a class="header-anchor" href="#du-统计磁盘上文件大小" aria-label="Permalink to &quot;du 统计磁盘上文件大小&quot;">​</a></h3><p><code>du [ 选项 ] [ 文件 ]</code></p><ul><li><code>-b</code> 以 byte 显示统计文件</li><li><code>-k</code> 以 kb 显示统计文件</li><li><code>-m</code> 以 mb 显示统计文件</li><li><code>-h</code> 以 <code>1024</code> 进制显示</li><li><code>-H</code> 以 <code>1000</code> 进制显示</li><li><code>-s</code> 只显示总和</li></ul><p>示例</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 以 1024 进制显示 /tmp 目录下所有文件大小</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">du</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -h</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> /tmp</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;"># 以 1024 进制显示 /tmp 目录下所有文件大小，只显示总和</span></span>
<span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">du</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -s</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> /tmp</span></span></code></pre></div><h3 id="fdisk-查看磁盘分区" tabindex="-1">fdisk 查看磁盘分区 <a class="header-anchor" href="#fdisk-查看磁盘分区" aria-label="Permalink to &quot;fdisk 查看磁盘分区&quot;">​</a></h3><p><code>fdisk [ 选项 ] 设备</code></p><ul><li><code>-l</code> 列出所有分区</li><li><code>-u</code> 与 <code>-l</code> 搭配，显示分区数目</li></ul><p>示例</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">fdisk</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -lu</span></span></code></pre></div><h2 id="vi-vim-编辑器" tabindex="-1">vi/vim 编辑器 <a class="header-anchor" href="#vi-vim-编辑器" aria-label="Permalink to &quot;vi/vim 编辑器&quot;">​</a></h2><p><img src="`+t+'" alt="alt text"></p><p><code>vim 文件名</code></p><h3 id="三种模式" tabindex="-1">三种模式 <a class="header-anchor" href="#三种模式" aria-label="Permalink to &quot;三种模式&quot;">​</a></h3><p><img src="'+c+'" alt="alt text"></p><h3 id="命令模式" tabindex="-1">命令模式 <a class="header-anchor" href="#命令模式" aria-label="Permalink to &quot;命令模式&quot;">​</a></h3><p>打开文件后默认进入命令模式，按照 <code>i o a</code> 进入编辑模式，按 <code>ESC</code> 键再次进入命令模式。</p><p>命令模式下，按 <code>:</code> 进入底线命令模式。</p><ul><li><code>Control + f</code> 向下翻页</li><li><code>Control + b</code> 向上翻页</li><li><code>0</code> 移动到行首</li><li><code>$</code> 移动到行尾</li><li><code>n + enter</code> 向下移动 n 行</li><li><code>n + space</code> 向右移动 n 个字符</li><li><code>gg</code> 移动到文档第一行</li><li><code>G</code> 移动到文档最后一行</li><li><code>dd</code> 删除光标所在行</li><li><code>ndd</code> 删除光标所在行向下 n 行</li><li><code>yy</code> 复制光标所在行</li><li><code>nyy</code> 复制光标所在行向下 n 行</li><li><code>p/P</code> p 粘贴到光标所在行下方，P 粘贴到光标所在行上方</li><li><code>u</code> 撤销上一次操作</li></ul><h3 id="底线命令模式" tabindex="-1">底线命令模式 <a class="header-anchor" href="#底线命令模式" aria-label="Permalink to &quot;底线命令模式&quot;">​</a></h3><p>在命令模式下输入 <code>:</code> 进入底线命令模式。</p><ul><li><code>w</code> 保存</li><li><code>q</code> 退出</li><li><code>q!</code> 强制退出，若曾修改过档案，又不想储存，使用 ! 为强制离开不储存档案</li><li><code>wq</code> 保存并退出</li><li><code>set nu</code> 显示行号</li><li><code>set nonu</code> 取消行号</li><li><code>ESC</code> 退出编辑模式，进入命令模式</li><li><code>%s/old/new</code> 替换光标所在行的第一个字符串, <code>%s/old/new/g</code> 替换行中所有字符串</li></ul><p><strong>命令和底线命令模式都能使用</strong></p><ul><li><code>/字符串</code> 向下搜索字符串</li><li><code>?字符串</code> 向上搜索字符串 <ul><li><code>n</code> 下一个</li><li><code>N</code> 上一个</li></ul></li></ul><h3 id="编辑模式" tabindex="-1">编辑模式 <a class="header-anchor" href="#编辑模式" aria-label="Permalink to &quot;编辑模式&quot;">​</a></h3><p>在命令模式下输入以下内容进行编辑模式。</p><ul><li><code>i</code> 在光标所在字符前插入</li><li><code>a</code> 在光标所在字符后插入</li><li><code>o</code> 在光标所在行下插入新行</li><li><code>ESC</code> 退出编辑模式，进入命令模式</li></ul><h2 id="磁盘管理" tabindex="-1">磁盘管理 <a class="header-anchor" href="#磁盘管理" aria-label="Permalink to &quot;磁盘管理&quot;">​</a></h2><h3 id="fdisk-管理磁盘分区" tabindex="-1">fdisk 管理磁盘分区 <a class="header-anchor" href="#fdisk-管理磁盘分区" aria-label="Permalink to &quot;fdisk 管理磁盘分区&quot;">​</a></h3><p><code>fdisk [ 选项 ] 设备</code></p><ul><li><code>-l</code> 列出所有分区</li><li><code>-u</code> 与 <code>-l</code> 搭配，显示分区数目</li></ul><p>示例</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">fdisk</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -lu</span></span></code></pre></div><p><code>fdisk /dev/sdb</code> 进入分区管理界面，输入 <code>m</code> 查看帮助信息。</p><p><img src="'+n+'" alt="alt text"></p>',61)]))}const v=i(p,[["render",h]]);export{F as __pageData,v as default};
